# Our magical spellbook to extract data from a PDF file
sub extract_data {
    my ($file) = @_;
    print "Opening the ancient tome: '$file'...\n";

    # Open the PDF file
    my $pdf = PDF::API2->open($file);

    # Initialize our spellbook to store extracted data
    my $spellbook = {
        date => undef,
        author => undef,
        tables => [],
    };

    # Iterate through each page
    for my $page (1 .. $pdf->pages) {
        my $text = $pdf->page($page)->extract_text;
        print "Reading page $page...\n";

        # Unidecode the text to handle non-ASCII characters
        $text = unidecode($text);

        # Spell out the date
        if ($text =~ /(\d{1,4})\/(\d{1,4})\/(\d{1,4})/) {
